22	
23	    logic                                   reconfigure;
24	    logic [                           31:0] immediate  ;
25	    logic [                            1:0] fu         ;
26	    logic [                            6:0] microop    ;
27	    logic [                            1:0] use_mask   ;
28	
29	    // [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0]
30	    logic [$clog2(32*DUMMY_VECTOR_LANES):0] maxvl      ;
31	    logic [$clog2(32*DUMMY_VECTOR_LANES):0] vl         ;
32	} to_vector;
33	//--------------------------------------
34	//Remapped Vector Instruction
35	typedef struct packed {
36	    logic                                   valid      ;
37	
38	    logic [                            4:0] dst        ;
39	    logic                                   dst_iszero ;
40	    logic [                            4:0] src1       ;
41	    logic                                   src1_iszero;
42	    logic [                            4:0] src2       ;
43	    logic                                   src2_iszero;
44	    logic [                            4:0] mask_src   ;
45	
46	    logic [                           31:0] data1      ;
47	    logic [                           31:0] data2      ;
48	
49	    logic                                   reconfigure;
50	    logic [                            4:0] ticket     ;
51	    logic [                           31:0] immediate  ;
52	    logic [                            1:0] fu         ;
53	    logic [                            6:0] microop    ;
54	    logic                                   use_mask   ;
55	    logic [                            1:0] lock       ;
56	
57	    // [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0]
58	    logic [$clog2(32*DUMMY_VECTOR_LANES):0] maxvl      ;
59	    logic [$clog2(32*DUMMY_VECTOR_LANES):0] vl         ;
60	} remapped_v_instr;
61	//--------------------------------------
62	//Remapped Memory Vector Instruction
63	typedef struct packed {
64	    logic                                   valid           ;
65	
66	    logic [                            4:0] dst             ;
67	    // logic                  dst_iszero ;
68	    logic [                            4:0] src1            ;
69	    // logic                  src1_iszero;
70	    logic [                            4:0] src2            ;
71	    // logic                  src2_iszero;
72	
73	    logic [                           31:0] data1           ;
74	    logic [                           31:0] data2           ;
75	
76	    logic [                            4:0] ticket          ;
77	    logic [                            4:0] last_ticket_src1;
78	    logic [                            4:0] last_ticket_src2;
79	    logic [                           31:0] immediate       ;
80	    logic [                            6:0] microop         ;
81	    logic                                   reconfigure     ;
